-- Step 1: Insert Stocks (21 EGX stocks)
ON CONFLICT ("ticker") DO UPDATE SET "price" = EXCLUDED."price", "marketCap" = EXCLUDED."marketCap", "updatedAt" = NOW();

-- Step 2: Insert Sector Stats (13 sectors)
ON CONFLICT ("sector") DO UPDATE SET "avgPE" = EXCLUDED."avgPE", "updatedAt" = NOW();

-- Step 3: Insert Economic Indicators (9 indicators)
ON CONFLICT ("name", "date") DO UPDATE SET "value" = EXCLUDED."value", "updatedAt" = NOW();

-- Step 4: Insert Market Params (Egypt-specific)
VALUES (0.19, 0.045, 0.085, 0.13, 0.225, 0.149, 0.025, 51.82, NOW(), 'CBE/Damodaran', NOW());

-- Step 5: Insert Financial Data (3 years x 21 stocks = 63 records)
ON CONFLICT ("stockId", "year", "quarter") DO UPDATE SET "revenue" = EXCLUDED."revenue", "lastUpdatedAt" = NOW();

-- Step 6: Insert Price History (last ~60 EGX trading days per stock)
ON CONFLICT ("stockId", "date") DO UPDATE SET "close" = EXCLUDED."close";

